import type { QAItem } from '../interview-data'

export const HTML_CSS_DATA: QAItem[] = [
  // === HTML: Cơ Bản (1-15) ===
  { id: 1, category: "HTML", subcategory: "Cơ Bản", level: "beginner", q: "HTML là gì? Nêu những đặc điểm chính của HTML?", a: "HTML (HyperText Markup Language) là ngôn ngữ đánh dấu siêu văn bản dùng để tạo cấu trúc trang web. Đặc điểm chính: sử dụng hệ thống thẻ (tags), hỗ trợ đa phương tiện, độc lập nền tảng, dễ học và sử dụng." },
  { id: 2, category: "HTML", subcategory: "Cơ Bản", level: "beginner", q: "Sự khác biệt giữa HTML, XHTML và HTML5 là gì?", a: "HTML cú pháp linh hoạt. XHTML tuân theo quy tắc XML nghiêm ngặt (phải đóng thẻ, viết thường). HTML5 là phiên bản mới nhất với nhiều API mới (Canvas, Geolocation, Web Storage) và thẻ semantic (header, nav, section)." },
  { id: 3, category: "HTML", subcategory: "Cơ Bản", level: "beginner", q: "DOCTYPE là gì? Tại sao cần khai báo DOCTYPE?", a: "DOCTYPE (Document Type Declaration) khai báo phiên bản HTML đang sử dụng, đặt ở dòng đầu tiên. HTML5 chỉ cần `<!DOCTYPE html>`. Giúp trình duyệt render đúng chuẩn (standards mode). Không có DOCTYPE → quirks mode: box model, CSS parsing khác nhau giữa các browsers, gây lỗi hiển thị." },
  { id: 4, category: "HTML", subcategory: "Cơ Bản", level: "beginner", q: "Cấu trúc cơ bản của một tài liệu HTML bao gồm những gì?", a: "Gồm: `<!DOCTYPE html>` khai báo loại tài liệu, `<html>` phần tử gốc, `<head>` chứa metadata (title, meta, link, script), và `<body>` chứa nội dung hiển thị trên trang." },
  { id: 5, category: "HTML", subcategory: "Cơ Bản", level: "beginner", q: "Thẻ `<head>` được sử dụng để làm gì?", a: "Chứa metadata của trang web, không hiển thị trực tiếp. Bao gồm: `<title>`, `<meta>` (charset, viewport, description), `<link>` (CSS), `<script>`, `<style>`, và các thẻ Open Graph." },
  { id: 6, category: "HTML", subcategory: "Cơ Bản", level: "beginner", q: "Thẻ `<body>` được sử dụng để làm gì?", a: "Chứa toàn bộ nội dung hiển thị trên trang web: văn bản, hình ảnh, video, form, bảng. Mỗi trang HTML chỉ có một thẻ `<body>`." },
  { id: 7, category: "HTML", subcategory: "Cơ Bản", level: "beginner", q: "Sự khác biệt giữa tag và element trong HTML là gì?", a: "Tag là cú pháp đánh dấu (`<p>`, `</p>`). Element là tổng thể gồm thẻ mở + nội dung + thẻ đóng (`<p>Hello</p>`). Một số element tự đóng như `<img>`, `<br>`, `<input>`." },
  { id: 8, category: "HTML", subcategory: "Cơ Bản", level: "beginner", q: "Element block và element inline khác nhau như thế nào?", a: "Block element chiếm toàn bộ chiều rộng, bắt đầu dòng mới (`<div>`, `<p>`, `<h1>`). Inline element chỉ chiếm chiều rộng cần thiết (`<span>`, `<a>`, `<strong>`). Block chứa được inline, nhưng thường không ngược lại. Ngoại lệ HTML5: `<a>` có thể bọc block elements." },
  { id: 9, category: "HTML", subcategory: "Cơ Bản", level: "beginner", q: "Những block-level element phổ biến có những gì?", a: "`<div>`, `<p>`, `<h1>`-`<h6>`, `<ul>`, `<ol>`, `<li>`, `<table>`, `<form>`, `<header>`, `<footer>`, `<section>`, `<article>`, `<nav>`, `<main>`, `<aside>`, `<blockquote>`, `<pre>`." },
  { id: 10, category: "HTML", subcategory: "Cơ Bản", level: "beginner", q: "Những inline element phổ biến có những gì?", a: "`<span>`, `<a>`, `<strong>`, `<em>`, `<img>`, `<input>`, `<button>`, `<label>`, `<code>`, `<br>`, `<small>`, `<sub>`, `<sup>`, `<abbr>`, `<cite>`." },
  { id: 11, category: "HTML", subcategory: "Cơ Bản", level: "beginner", q: "Inline-block element là gì?", a: "Kết hợp đặc tính inline và block: hiển thị trên cùng dòng như inline nhưng có thể set width/height/margin/padding như block. Dùng CSS `display: inline-block`. Ứng dụng phổ biến: tạo navigation menu ngang, grid layout đơn giản, buttons cạnh nhau. Khác inline: có thể set kích thước. Khác block: không chiếm hết dòng." },
  { id: 12, category: "HTML", subcategory: "Cơ Bản", level: "beginner", q: "Attribute là gì? Cho ví dụ?", a: "Attribute cung cấp thông tin bổ sung cho HTML element, nằm trong thẻ mở. Ví dụ: `href`, `src`, `class`, `id`, `style`, `alt`, `title`, `placeholder`, `disabled`, `type`." },
  { id: 13, category: "HTML", subcategory: "Cơ Bản", level: "beginner", q: "Boolean attribute là gì? Cho ví dụ?", a: "Attribute chỉ có hai trạng thái: có hoặc không. Khi xuất hiện = true, vắng mặt = false. Ví dụ: `disabled`, `checked`, `selected`, `required`, `readonly`, `autofocus`, `hidden`." },
  { id: 14, category: "HTML", subcategory: "Cơ Bản", level: "beginner", q: "Custom attribute (data-*) là gì?", a: "Cho phép lưu trữ dữ liệu tùy chỉnh trên HTML element mà không vi phạm HTML spec. Cú pháp: `data-user-id=\"123\"`. Truy cập qua JS bằng `element.dataset.userId` (tự convert kebab-case sang camelCase). Ứng dụng: truyền data từ HTML sang JS, CSS selectors (`[data-active]`), testing (data-testid). React dùng data attributes để pass info cho DOM." },
  { id: 15, category: "HTML", subcategory: "Cơ Bản", level: "intermediate", q: "Thuộc tính `id` và `class` khác nhau như thế nào?", a: "`id` là duy nhất trên toàn trang, chỉ gán cho 1 element. `class` có thể dùng lại cho nhiều elements. CSS specificity của id cao hơn class. id dùng cho JS targeting, class dùng cho styling." },

  // === HTML: Semantic (16-30) ===
  { id: 16, category: "HTML", subcategory: "Semantic", level: "beginner", q: "Semantic HTML là gì? Tại sao quan trọng?", a: "Semantic HTML dùng thẻ có ý nghĩa mô tả nội dung (`<article>`, `<nav>`, `<header>`, `<main>`, `<aside>`) thay vì thẻ chung (`<div>`, `<span>`). Quan trọng vì: (1) SEO — search engines hiểu cấu trúc trang tốt hơn. (2) Accessibility — screen readers navigate bằng semantic landmarks. (3) Maintainability — code tự mô tả, đọc hiểu nhanh hơn. (4) Consistency — team dùng cùng conventions." },
  { id: 17, category: "HTML", subcategory: "Semantic", level: "beginner", q: "Sự khác biệt giữa `<div>` và `<section>` là gì?", a: "`<div>` là container chung, không có ý nghĩa ngữ nghĩa. `<section>` đại diện cho phần nội dung có chủ đề liên quan, thường có heading. Dùng `<section>` khi nội dung có logic nhóm rõ ràng." },
  { id: 18, category: "HTML", subcategory: "Semantic", level: "beginner", q: "`<article>` và `<section>` khác nhau thế nào?", a: "`<article>` là nội dung độc lập, tự đầy đủ (bài viết, bình luận, sản phẩm). `<section>` là nhóm nội dung liên quan trong cùng ngữ cảnh. Article có thể chứa nhiều section và ngược lại." },
  { id: 19, category: "HTML", subcategory: "Semantic", level: "beginner", q: "`<header>`, `<footer>`, `<nav>`, `<main>`, `<aside>` dùng khi nào?", a: "`<header>`: phần giới thiệu/navigation. `<footer>`: copyright, liên hệ. `<nav>`: navigation chính. `<main>`: nội dung chính duy nhất. `<aside>`: nội dung liên quan gián tiếp (sidebar)." },
  { id: 20, category: "HTML", subcategory: "Semantic", level: "beginner", q: "`<figure>` và `<figcaption>` dùng để làm gì?", a: "`<figure>` nhóm nội dung minh họa (hình ảnh, biểu đồ, code snippet). `<figcaption>` là chú thích bên trong `<figure>`. Có thể tách ra mà không ảnh hưởng luồng nội dung chính." },
  { id: 21, category: "HTML", subcategory: "Semantic", level: "intermediate", q: "`<mark>`, `<strong>`, `<em>` khác nhau thế nào?", a: "`<mark>` highlight text (nền vàng). `<strong>` nhấn mạnh tầm quan trọng (in đậm). `<em>` nhấn mạnh ngữ điệu (in nghiêng). Cả ba có ý nghĩa ngữ nghĩa, khác `<b>`, `<i>` chỉ visual." },
  { id: 22, category: "HTML", subcategory: "Semantic", level: "intermediate", q: "Thẻ `<time>` được sử dụng để làm gì?", a: "Đánh dấu ngày/giờ theo format machine-readable. Attribute `datetime` chứa giá trị ISO 8601. Ví dụ: `<time datetime=\"2024-03-15\">15/3/2024</time>`. Giúp SEO và accessibility." },
  { id: 23, category: "HTML", subcategory: "Semantic", level: "intermediate", q: "Semantic HTML ảnh hưởng SEO như thế nào?", a: "Search engines dùng semantic HTML để hiểu cấu trúc nội dung. `<article>` xác định nội dung chính, `<nav>` hiểu cấu trúc site, `<h1>`-`<h6>` xác định hierarchy. Trang semantic được index tốt hơn." },
  { id: 24, category: "HTML", subcategory: "Semantic", level: "intermediate", q: "Khi nào dùng `<dl>`, `<dt>`, `<dd>`?", a: "Description list dùng cho cặp thuật ngữ-định nghĩa. `<dl>` bọc danh sách, `<dt>` là thuật ngữ, `<dd>` là mô tả. Phù hợp cho FAQ, glossary, metadata key-value." },
  { id: 25, category: "HTML", subcategory: "Semantic", level: "intermediate", q: "Thẻ `<details>` và `<summary>` hoạt động thế nào?", a: "`<details>` tạo widget mở/đóng native không cần JS. `<summary>` là tiêu đề hiển thị khi đóng. Click vào summary sẽ toggle nội dung bên trong. Hỗ trợ attribute `open` để mặc định mở." },

  // === HTML: HTML5 Features (26-40) ===
  { id: 26, category: "HTML", subcategory: "HTML5", level: "beginner", q: "HTML5 có những tính năng mới nào so với HTML4?", a: "Thẻ semantic (header, nav, article), Canvas/SVG, Audio/Video native, Web Storage (localStorage/sessionStorage), Geolocation API, Web Workers, Form validation, Drag & Drop API, WebSocket." },
  { id: 27, category: "HTML", subcategory: "HTML5", level: "beginner", q: "Canvas và SVG khác nhau thế nào?", a: "Canvas là pixel-based (raster), vẽ bằng JavaScript, tốt cho game/animation phức tạp. SVG là vector-based (XML), scale không mất chất lượng, tốt cho icon/chart/logo. SVG accessible hơn vì là DOM elements." },
  { id: 28, category: "HTML", subcategory: "HTML5", level: "intermediate", q: "Local Storage và Session Storage khác nhau thế nào?", a: "Local Storage lưu vĩnh viễn (cho đến khi xóa thủ công), ~5MB per origin. Session Storage chỉ tồn tại trong phiên (đóng tab = mất). Cả hai lưu key-value dạng string, không gửi lên server như cookies." },
  { id: 29, category: "HTML", subcategory: "HTML5", level: "intermediate", q: "Web Worker là gì?", a: "Chạy JavaScript trong background thread riêng, không block UI thread chính. Dùng cho tác vụ nặng (xử lý dữ liệu, tính toán). Giao tiếp qua `postMessage()`. Không truy cập được DOM." },
  { id: 30, category: "HTML", subcategory: "HTML5", level: "intermediate", q: "Service Worker là gì? Khác Web Worker thế nào?", a: "Service Worker là proxy giữa browser và network, cho phép offline caching, push notifications, background sync. Khác Web Worker: Service Worker persist qua sessions, can thiệp network requests, dùng cho PWA." },
  { id: 31, category: "HTML", subcategory: "HTML5", level: "intermediate", q: "Progressive Web App (PWA) là gì?", a: "Ứng dụng web có trải nghiệm gần native app: offline, installable, push notifications. Yêu cầu: HTTPS, Service Worker, Web App Manifest. Dùng manifest.json khai báo icon, theme, start_url." },
  { id: 32, category: "HTML", subcategory: "HTML5", level: "intermediate", q: "IndexedDB là gì? Khi nào nên dùng?", a: "Database NoSQL trong browser, lưu trữ lượng lớn structured data (vượt 5MB của localStorage). API async, hỗ trợ index, transactions. Dùng cho offline-first apps, caching lớn, phức tạp hơn localStorage." },
  { id: 33, category: "HTML", subcategory: "HTML5", level: "advanced", q: "Geolocation API hoạt động thế nào?", a: "Truy cập vị trí thiết bị qua `navigator.geolocation.getCurrentPosition()`. Yêu cầu permission từ user. Trả về latitude/longitude/accuracy. Có `watchPosition()` theo dõi liên tục. Chỉ hoạt động trên HTTPS." },
  { id: 34, category: "HTML", subcategory: "HTML5", level: "advanced", q: "History API dùng để làm gì?", a: "Cho phép thao tác browser history mà không reload trang. `pushState()` thêm entry mới, `replaceState()` thay entry hiện tại, `popstate` event lắng nghe back/forward. Nền tảng cho SPA routing." },
  { id: 35, category: "HTML", subcategory: "HTML5", level: "advanced", q: "WebSocket khác HTTP thế nào?", a: "HTTP là request-response (client khởi tạo). WebSocket là full-duplex, persistent connection cho phép server push data real-time. Handshake qua HTTP rồi upgrade. Dùng cho chat, live feed, multiplayer game." },
  { id: 36, category: "HTML", subcategory: "HTML5", level: "advanced", q: "Intersection Observer API là gì?", a: "API async theo dõi khi element xuất hiện/biến mất khỏi viewport. Thay thế scroll event listener (tốn performance). Dùng cho lazy loading images, infinite scroll, trigger animations khi element visible." },
  { id: 37, category: "HTML", subcategory: "HTML5", level: "advanced", q: "MutationObserver là gì?", a: "API theo dõi thay đổi DOM (thêm/xóa nodes, thay đổi attributes, text content). Thay thế Mutation Events (deprecated). Dùng cho tracking DOM changes, auto-formatting, accessibility monitoring." },
  { id: 38, category: "HTML", subcategory: "HTML5", level: "advanced", q: "ResizeObserver là gì?", a: "API theo dõi khi element thay đổi kích thước. Hiệu quả hơn window resize event vì target specific elements. Dùng cho responsive components, chart resizing, dynamic layouts không phụ thuộc media queries." },
  { id: 39, category: "HTML", subcategory: "HTML5", level: "advanced", q: "Drag and Drop API hoạt động thế nào?", a: "Cho phép kéo-thả elements native. Events: `dragstart`, `drag`, `dragover`, `drop`, `dragend`. Dùng `dataTransfer` object để truyền data. Cần `e.preventDefault()` trên `dragover` để cho phép drop." },
  { id: 40, category: "HTML", subcategory: "HTML5", level: "advanced", q: "Web Components gồm những công nghệ nào?", a: "Gồm 3 công nghệ: Custom Elements (tạo thẻ HTML tùy chỉnh), Shadow DOM (encapsulate styles/markup), HTML Templates (`<template>` và `<slot>`). Cho phép tạo reusable components không phụ thuộc framework." },

  // === HTML: Forms (41-60) ===
  { id: 41, category: "HTML", subcategory: "Forms", level: "beginner", q: "Method GET và POST khác nhau thế nào?", a: "GET gửi dữ liệu qua URL (query string), giới hạn kích thước, có thể bookmark. POST gửi trong body request, không giới hạn kích thước. Lưu ý: POST không tự bảo mật hơn GET — cần HTTPS để bảo vệ dữ liệu. GET cho truy vấn, POST cho dữ liệu lớn/thay đổi state." },
  { id: 42, category: "HTML", subcategory: "Forms", level: "beginner", q: "Các input types trong HTML5 có những gì?", a: "text, password, email, number, tel, url, date, time, datetime-local, month, week, color, range, file, checkbox, radio, hidden, search, submit, reset, button. Mỗi type có validation và UI riêng." },
  { id: 43, category: "HTML", subcategory: "Forms", level: "beginner", q: "`<label>` element quan trọng thế nào?", a: "Liên kết text với form control qua `for` attribute hoặc wrapping. Click label = focus input. Quan trọng cho accessibility: screen readers đọc label khi focus input. Tăng click area trên mobile." },
  { id: 44, category: "HTML", subcategory: "Forms", level: "beginner", q: "`<select>` và `<datalist>` khác nhau thế nào?", a: "`<select>` là dropdown chọn từ danh sách cố định. `<datalist>` gợi ý cho input text, user vẫn có thể nhập giá trị tùy ý. datalist linh hoạt hơn, select kiểm soát chặt hơn." },
  { id: 45, category: "HTML", subcategory: "Forms", level: "beginner", q: "`<fieldset>` và `<legend>` dùng để làm gì?", a: "`<fieldset>` nhóm các form controls liên quan, tạo border visual. `<legend>` là tiêu đề cho fieldset. Cải thiện accessibility và tổ chức form phức tạp. Screen readers đọc legend cho mỗi group." },
  { id: 46, category: "HTML", subcategory: "Forms", level: "intermediate", q: "HTML5 form validation có những attribute nào?", a: "`required` (bắt buộc), `pattern` (regex), `min`/`max` (số/ngày), `minlength`/`maxlength` (chuỗi), `step` (bước nhảy). Input type email/url tự validate format. Dùng `:valid`/`:invalid` CSS pseudo-classes." },
  { id: 47, category: "HTML", subcategory: "Forms", level: "intermediate", q: "`readonly` và `disabled` khác nhau thế nào?", a: "`readonly`: user không thể sửa nhưng giá trị vẫn submit cùng form. `disabled`: user không tương tác được, giá trị KHÔNG submit. disabled thay đổi visual (mờ), readonly giữ nguyên." },
  { id: 48, category: "HTML", subcategory: "Forms", level: "intermediate", q: "Enctype attribute có những giá trị nào?", a: "`application/x-www-form-urlencoded` (mặc định, encode key=value). `multipart/form-data` (bắt buộc khi upload file). `text/plain` (không encode, dùng cho debug). Upload file phải dùng multipart." },
  { id: 49, category: "HTML", subcategory: "Forms", level: "intermediate", q: "Autocomplete attribute hoạt động thế nào?", a: "Gợi ý trình duyệt tự điền form. Values: `on`/`off`, hoặc cụ thể: `name`, `email`, `tel`, `address-line1`, `cc-number`. Cải thiện UX, giảm nhập liệu. Có thể set trên form hoặc từng input." },
  { id: 50, category: "HTML", subcategory: "Forms", level: "intermediate", q: "Constraint Validation API là gì?", a: "API JavaScript kiểm tra và tùy chỉnh form validation. Methods: `checkValidity()`, `reportValidity()`, `setCustomValidity()`. Properties: `validity.valueMissing`, `validity.typeMismatch`. Override message lỗi mặc định của browser." },
  { id: 51, category: "HTML", subcategory: "Forms", level: "intermediate", q: "FormData API dùng để làm gì?", a: "Thu thập dữ liệu form dạng key-value pairs. `new FormData(formElement)` tự động lấy tất cả fields. Hỗ trợ file upload. Dùng với `fetch()` để submit form bằng JavaScript. Methods: `append()`, `get()`, `entries()`." },
  { id: 52, category: "HTML", subcategory: "Forms", level: "advanced", q: "`<input type='file'>` có những tính năng gì?", a: "`accept` giới hạn file type (`.jpg,.png`, `image/*`). `multiple` cho phép chọn nhiều file. `capture` mở camera trên mobile. Truy cập files qua `input.files` (FileList). Dùng FileReader để đọc content." },
  { id: 53, category: "HTML", subcategory: "Forms", level: "advanced", q: "Làm thế nào để tạo custom form validation?", a: "Dùng `setCustomValidity(message)` trên input element. Message rỗng = valid. Kết hợp `pattern` attribute với regex, lắng nghe `invalid` event. Có thể dùng `novalidate` trên form rồi validate bằng JS." },
  { id: 54, category: "HTML", subcategory: "Forms", level: "advanced", q: "Content Editable là gì?", a: "`contenteditable=\"true\"` biến bất kỳ element nào thành editable. Dùng cho rich text editors. Kết hợp `document.execCommand()` (deprecated) hoặc Selection/Range API. Khó kiểm soát output HTML." },
  { id: 55, category: "HTML", subcategory: "Forms", level: "advanced", q: "Làm sao tối ưu form cho mobile?", a: "Dùng đúng input type (email, tel, number) để hiện đúng keyboard. Set `inputmode` attribute. Dùng `autocomplete` hints. Touch-friendly size (min 44x44px). Label rõ ràng. Tránh hover-only interactions." },

  // === HTML: Accessibility (56-70) ===
  { id: 56, category: "HTML", subcategory: "Accessibility", level: "beginner", q: "Accessibility (a11y) là gì? Tại sao quan trọng?", a: "Khả năng tiếp cận web cho mọi người, bao gồm người khuyết tật (thị giác, thính giác, vận động). Quan trọng vì: đạo đức, luật pháp (ADA, WCAG), mở rộng đối tượng users, cải thiện SEO và UX." },
  { id: 57, category: "HTML", subcategory: "Accessibility", level: "beginner", q: "ARIA là gì?", a: "ARIA (Accessible Rich Internet Applications) là tập hợp attributes bổ sung accessibility cho HTML khi semantic không đủ. 3 loại: (1) Roles — xác định vai trò (`role=\"button\"`, `role=\"dialog\"`). (2) States — trạng thái (`aria-expanded=\"true\"`, `aria-disabled`). (3) Properties — thuộc tính (`aria-label`, `aria-describedby`). Nguyên tắc: dùng native HTML trước, ARIA là giải pháp cuối cùng." },
  { id: 58, category: "HTML", subcategory: "Accessibility", level: "beginner", q: "Alt text quan trọng thế nào?", a: "Mô tả hình ảnh cho screen readers và khi ảnh không load được. Ảnh decorative dùng `alt=\"\"` (rỗng). Ảnh thông tin cần mô tả ngắn gọn, chính xác. Quan trọng cho SEO image search." },
  { id: 59, category: "HTML", subcategory: "Accessibility", level: "intermediate", q: "WCAG là gì? Có bao nhiêu cấp độ?", a: "Web Content Accessibility Guidelines - tiêu chuẩn quốc tế về accessibility. 3 cấp: A (cơ bản), AA (khuyến nghị, yêu cầu pháp lý), AAA (cao nhất). 4 nguyên tắc: Perceivable, Operable, Understandable, Robust." },
  { id: 60, category: "HTML", subcategory: "Accessibility", level: "intermediate", q: "aria-label, aria-labelledby, aria-describedby khác nhau?", a: "`aria-label` gán label trực tiếp bằng string. `aria-labelledby` reference đến id của element chứa label. `aria-describedby` thêm mô tả bổ sung. labelledby override aria-label. describedby là thông tin phụ." },
  { id: 61, category: "HTML", subcategory: "Accessibility", level: "intermediate", q: "Keyboard navigation quan trọng thế nào?", a: "Nhiều users chỉ dùng keyboard (khuyết tật vận động, screen reader users). Tất cả interactive elements phải focusable và operable bằng keyboard. Tab để navigate, Enter/Space để activate, Escape để đóng." },
  { id: 62, category: "HTML", subcategory: "Accessibility", level: "intermediate", q: "tabindex attribute hoạt động thế nào?", a: "`tabindex=\"0\"`: thêm element vào tab order tự nhiên. `tabindex=\"-1\"`: focusable bằng JS nhưng không tab được. `tabindex > 0`: đặt thứ tự ưu tiên (tránh dùng, gây confuse). Mặc định: links, buttons, inputs đã focusable." },
  { id: 63, category: "HTML", subcategory: "Accessibility", level: "intermediate", q: "Color contrast yêu cầu gì theo WCAG?", a: "AA: tỷ lệ tối thiểu 4.5:1 cho text thường, 3:1 cho text lớn (18px+ hoặc 14px+ bold). AAA: 7:1 và 4.5:1. Dùng tools như Lighthouse, axe, hoặc WebAIM Contrast Checker để kiểm tra." },
  { id: 64, category: "HTML", subcategory: "Accessibility", level: "advanced", q: "aria-live dùng khi nào?", a: "Thông báo cho screen readers về nội dung thay đổi động. `polite`: đợi user idle rồi đọc. `assertive`: ngắt ngay để đọc. Dùng cho notifications, chat messages, live search results, form errors." },
  { id: 65, category: "HTML", subcategory: "Accessibility", level: "advanced", q: "Skip links là gì và tại sao cần?", a: "Link ẩn ở đầu trang, hiện khi focus, cho phép nhảy thẳng đến main content. Giúp keyboard/screen reader users không phải tab qua navigation mỗi lần. Thường implement với anchor link + CSS." },
  { id: 66, category: "HTML", subcategory: "Accessibility", level: "advanced", q: "Focus management trong SPA quan trọng thế nào?", a: "Khi route thay đổi trong SPA, focus phải chuyển đến nội dung mới (heading hoặc main). Không có page reload tự nhiên nên screen readers không biết nội dung đổi. Dùng `focus()` và `aria-live` regions." },
  { id: 67, category: "HTML", subcategory: "Accessibility", level: "advanced", q: "Heading hierarchy (h1-h6) tại sao quan trọng?", a: "Screen readers dùng headings để navigate nhanh. Phải theo thứ tự (h1 → h2 → h3), không nhảy cấp. Mỗi trang chỉ 1 `<h1>`. Headings tạo outline cho document, giúp mọi users hiểu cấu trúc." },

  // === HTML: SEO (68-80) ===
  { id: 68, category: "HTML", subcategory: "SEO", level: "beginner", q: "Meta description là gì?", a: "Thẻ meta mô tả ngắn gọn nội dung trang (150-160 ký tự). Hiển thị trong search results. Không trực tiếp ảnh hưởng ranking nhưng tăng CTR (click-through rate). Mỗi trang nên có meta description unique." },
  { id: 69, category: "HTML", subcategory: "SEO", level: "beginner", q: "Open Graph meta tags là gì?", a: "Meta tags (og:title, og:description, og:image, og:url) kiểm soát cách trang hiển thị khi chia sẻ trên mạng xã hội (Facebook, LinkedIn). Twitter dùng twitter:card riêng. Quan trọng cho social media marketing." },
  { id: 70, category: "HTML", subcategory: "SEO", level: "intermediate", q: "Canonical tag dùng để làm gì?", a: "`<link rel=\"canonical\" href=\"...\">` chỉ định URL chính thức khi có nhiều URL cùng nội dung (duplicate content). Giúp search engines consolidate ranking signals về 1 URL, tránh penalize duplicate." },
  { id: 71, category: "HTML", subcategory: "SEO", level: "intermediate", q: "Structured data (Schema.org) là gì?", a: "Markup dữ liệu có cấu trúc giúp search engines hiểu nội dung tốt hơn. Dùng JSON-LD (khuyến nghị), Microdata hoặc RDFa. Cho phép rich snippets (rating, price, FAQ) trong kết quả tìm kiếm." },
  { id: 72, category: "HTML", subcategory: "SEO", level: "intermediate", q: "Robots meta tag và robots.txt khác nhau?", a: "Meta robots (`<meta name=\"robots\" content=\"noindex,nofollow\">`) áp dụng per-page. robots.txt áp dụng toàn site, ngăn crawlers truy cập paths cụ thể. robots.txt không ngăn indexing nếu page có backlinks." },
  { id: 73, category: "HTML", subcategory: "SEO", level: "intermediate", q: "Sitemap XML quan trọng thế nào?", a: "Danh sách URLs giúp search engines phát hiện và crawl trang hiệu quả. Quan trọng cho site lớn, trang mới, trang ít backlinks. Chứa URL, lastmod, changefreq, priority. Submit qua Google Search Console." },
  { id: 74, category: "HTML", subcategory: "SEO", level: "advanced", q: "Core Web Vitals ảnh hưởng SEO thế nào?", a: "Google dùng Core Web Vitals (LCP, INP, CLS) làm ranking factor. LCP: thời gian load element lớn nhất (<2.5s). CLS: layout shift (<0.1). INP (thay thế FID từ 3/2024): phản hồi tương tác (<200ms). Ảnh hưởng cả mobile và desktop ranking." },
  { id: 75, category: "HTML", subcategory: "SEO", level: "advanced", q: "Hreflang attribute dùng khi nào?", a: "Cho search engines biết trang có phiên bản ngôn ngữ/vùng miền khác. `<link rel=\"alternate\" hreflang=\"vi\" href=\"...\">`. Tránh duplicate content giữa các phiên bản ngôn ngữ. Phải có hreflang 2 chiều." },

  // === CSS: Cơ Bản (76-90) ===
  { id: 76, category: "CSS", subcategory: "Cơ Bản", level: "beginner", q: "CSS là gì? Có mấy cách sử dụng CSS?", a: "CSS (Cascading Style Sheets) định dạng giao diện HTML. 3 cách: Inline (attribute style), Internal (thẻ `<style>` trong head), External (file .css riêng qua `<link>`). External được khuyến nghị nhất vì tách biệt và tái sử dụng." },
  { id: 77, category: "CSS", subcategory: "Cơ Bản", level: "beginner", q: "Cascade trong CSS nghĩa là gì?", a: "Cơ chế quyết định style nào được áp dụng khi có xung đột. Thứ tự ưu tiên: importance (!important) > specificity > source order. Browser default < user styles < author styles. Cascade giúp quản lý styles phức tạp." },
  { id: 78, category: "CSS", subcategory: "Cơ Bản", level: "beginner", q: "Specificity trong CSS được tính thế nào?", a: "Specificity tính theo 3 cột (a,b,c): inline (1,0,0,0) > ID (0,1,0,0) > class/pseudo-class (0,0,1,0) > element (0,0,0,1). Không cộng dồn giữa các cột. Ví dụ: `#nav .link:hover` = 100+10+10 = 120. Specificity cao hơn thắng, bằng nhau thì source order quyết định." },
  { id: 79, category: "CSS", subcategory: "Cơ Bản", level: "beginner", q: "Inheritance trong CSS là gì?", a: "Một số CSS properties tự động kế thừa từ parent sang child (color, font-family, font-size, line-height). Các properties về box model (margin, padding, border) KHÔNG kế thừa. Dùng `inherit`, `initial`, `unset` để override." },
  { id: 80, category: "CSS", subcategory: "Cơ Bản", level: "beginner", q: "Đơn vị px, em, rem, %, vw, vh khác nhau?", a: "`px`: tuyệt đối. `em`: relative với font-size parent. `rem`: relative với root (html) font-size. `%`: relative với parent. `vw`/`vh`: % viewport width/height. rem được khuyến nghị cho responsive design." },
  { id: 81, category: "CSS", subcategory: "Cơ Bản", level: "beginner", q: "!important dùng khi nào? Tại sao nên tránh?", a: "Override tất cả specificity rules. Nên tránh vì: khó debug, khó maintain, phá vỡ cascade tự nhiên. Chỉ dùng cho utility classes hoặc override third-party styles khi không có cách khác." },
  { id: 82, category: "CSS", subcategory: "Cơ Bản", level: "intermediate", q: "CSS reset và normalize CSS khác nhau?", a: "CSS Reset xóa toàn bộ browser default styles (margin, padding = 0). Normalize CSS giữ các default hữu ích, chỉ sửa inconsistencies giữa browsers. Normalize phổ biến hơn vì giữ được base styling hợp lý." },
  { id: 83, category: "CSS", subcategory: "Cơ Bản", level: "intermediate", q: "SASS/SCSS là gì? Lợi ích?", a: "CSS preprocessor thêm tính năng: variables ($color), nesting, mixins, functions, partials, inheritance (@extend). `.scss` dùng cú pháp giống CSS (curly braces), `.sass` dùng indentation. Modern Sass: dùng `@use`/`@forward` thay `@import` (deprecated). Compile ra CSS thuần." },

  // === CSS: Selectors (84-95) ===
  { id: 84, category: "CSS", subcategory: "Selectors", level: "beginner", q: "Pseudo-class và pseudo-element khác nhau?", a: "Pseudo-class chọn state của element (`:hover`, `:focus`, `:first-child`, `:nth-child`). Pseudo-element tạo/chọn phần ảo (::before, ::after, ::first-line). Pseudo-class dùng 1 dấu hai chấm, pseudo-element dùng 2." },
  { id: 85, category: "CSS", subcategory: "Selectors", level: "beginner", q: ":nth-child() và :nth-of-type() khác nhau?", a: "`:nth-child(n)` đếm tất cả siblings. `:nth-of-type(n)` chỉ đếm siblings cùng tag. Ví dụ: `p:nth-child(2)` = phần tử thứ 2 NẾU là p. `p:nth-of-type(2)` = phần tử p thứ 2 bất kể vị trí." },
  { id: 86, category: "CSS", subcategory: "Selectors", level: "intermediate", q: "::before và ::after dùng để làm gì?", a: "Tạo pseudo-element trước/sau content của element. Bắt buộc có `content` property. Dùng cho decorative elements (icons, shapes, borders), tooltips, clearfix. Không nên dùng cho nội dung quan trọng (screen readers có thể bỏ qua)." },
  { id: 87, category: "CSS", subcategory: "Selectors", level: "intermediate", q: ":has() selector là gì?", a: "Parent selector trong CSS (trước đây không có). Chọn element có chứa selector con. Ví dụ: `article:has(img)` chọn article có chứa img. `div:has(> p)` chọn div có p là direct child. Game-changer cho CSS." },
  { id: 88, category: "CSS", subcategory: "Selectors", level: "intermediate", q: "Combinator selectors (>, +, ~, space) khác nhau?", a: "Space (descendant): bất kỳ con cháu nào. `>` (child): chỉ con trực tiếp. `+` (adjacent sibling): anh em liền kề ngay sau. `~` (general sibling): tất cả anh em sau. Ví dụ: `div > p` vs `div p`." },
  { id: 89, category: "CSS", subcategory: "Selectors", level: "intermediate", q: "Attribute selectors có những dạng nào?", a: "`[attr]`: có attribute. `[attr=value]`: giá trị chính xác. `[attr^=value]`: bắt đầu bằng. `[attr$=value]`: kết thúc bằng. `[attr*=value]`: chứa. `[attr~=value]`: chứa word. Case-insensitive với `i` flag." },
  { id: 90, category: "CSS", subcategory: "Selectors", level: "advanced", q: ":is(), :where(), :not() khác nhau?", a: "`:is()` và `:where()` đều match danh sách selectors, nhưng `:is()` giữ specificity cao nhất trong danh sách, `:where()` luôn specificity = 0. `:not()` loại trừ selector. Cả ba giúp viết CSS ngắn gọn hơn." },

  // === CSS: Box Model & Layout (91-110) ===
  { id: 91, category: "CSS", subcategory: "Box Model", level: "beginner", q: "Box model gồm những gì?", a: "4 lớp từ trong ra: content (nội dung), padding (khoảng đệm), border (viền), margin (khoảng cách ngoài). Mặc định width/height chỉ tính content. Dùng `box-sizing: border-box` để tính luôn padding + border." },
  { id: 92, category: "CSS", subcategory: "Box Model", level: "beginner", q: "box-sizing: content-box vs border-box?", a: "`content-box` (mặc định): width/height chỉ tính content, padding+border cộng thêm. `border-box`: width/height bao gồm content+padding+border. border-box dễ quản lý hơn, nên dùng `* { box-sizing: border-box }`." },
  { id: 93, category: "CSS", subcategory: "Box Model", level: "intermediate", q: "Margin collapsing là gì?", a: "Khi 2 vertical margins tiếp xúc nhau, chúng merge thành 1 margin (lấy giá trị lớn hơn). Xảy ra giữa siblings, parent-child (không có padding/border ngăn cách). Không xảy ra với horizontal margins, flexbox, grid items." },
  { id: 94, category: "CSS", subcategory: "Box Model", level: "intermediate", q: "Overflow property có những giá trị nào?", a: "`visible` (mặc định, tràn ra ngoài). `hidden` (cắt nội dung tràn). `scroll` (luôn hiện scrollbar). `auto` (scrollbar khi cần). `clip` (như hidden nhưng cấm programmatic scroll). Dùng `overflow-x`/`overflow-y` riêng." },
  { id: 95, category: "CSS", subcategory: "Display & Position", level: "beginner", q: "display: none, visibility: hidden, opacity: 0 khác nhau?", a: "`display: none`: xóa khỏi layout, không chiếm không gian. `visibility: hidden`: ẩn nhưng vẫn chiếm không gian. `opacity: 0`: trong suốt, vẫn chiếm không gian VÀ nhận events. none không animatable." },
  { id: 96, category: "CSS", subcategory: "Display & Position", level: "beginner", q: "Position property có những giá trị nào?", a: "`static` (mặc định, theo flow). `relative` (offset từ vị trí gốc, vẫn chiếm space). `absolute` (thoát flow, relative với positioned ancestor). `fixed` (relative với viewport). `sticky` (hybrid relative+fixed)." },
  { id: 97, category: "CSS", subcategory: "Display & Position", level: "intermediate", q: "Position sticky hoạt động thế nào?", a: "Kết hợp relative và fixed. Element scroll bình thường cho đến khi đạt threshold (top/bottom), sau đó 'dính' tại vị trí đó. Cần set ít nhất 1 trong top/right/bottom/left. Parent phải có overflow visible." },
  { id: 98, category: "CSS", subcategory: "Display & Position", level: "intermediate", q: "Z-index hoạt động thế nào?", a: "Kiểm soát thứ tự xếp chồng (stacking order) của positioned elements. Giá trị cao hơn nằm trên. Chỉ hoạt động với position khác static. Tạo stacking context mới với z-index + positioned hoặc opacity < 1." },
  { id: 99, category: "CSS", subcategory: "Display & Position", level: "intermediate", q: "Stacking context là gì?", a: "Nhóm 3D ảo chứa các elements cùng xếp chồng. Được tạo bởi: root element, positioned + z-index, opacity < 1, transform, filter. Z-index chỉ so sánh trong cùng stacking context, không xuyên qua." },
  { id: 100, category: "CSS", subcategory: "Display & Position", level: "advanced", q: "Transform có ảnh hưởng layout không?", a: "Không. Transform (translate, rotate, scale) chỉ thay đổi visual, không ảnh hưởng flow layout. Element vẫn chiếm space gốc. Tạo stacking context mới. Translate tốt hơn top/left cho animations vì dùng GPU compositing." },

  // === CSS: Flexbox (101-115) ===
  { id: 101, category: "CSS", subcategory: "Flexbox", level: "beginner", q: "Flexbox là gì? Khi nào nên dùng?", a: "Layout 1 chiều (row hoặc column) cho phép căn chỉnh, phân bổ không gian linh hoạt giữa items. Dùng cho: navigation bars, card layouts, centering, form layouts. Grid phù hợp hơn cho layout 2 chiều." },
  { id: 102, category: "CSS", subcategory: "Flexbox", level: "beginner", q: "justify-content và align-items khác nhau?", a: "`justify-content` căn chỉnh theo main axis (mặc định horizontal): flex-start, center, flex-end, space-between, space-around, space-evenly. `align-items` căn theo cross axis (mặc định vertical): stretch, center, flex-start, flex-end, baseline." },
  { id: 103, category: "CSS", subcategory: "Flexbox", level: "beginner", q: "flex-direction có những giá trị nào?", a: "`row` (mặc định, trái→phải). `row-reverse` (phải→trái). `column` (trên→dưới). `column-reverse` (dưới→trên). Thay đổi direction cũng đổi main/cross axis, ảnh hưởng justify-content/align-items." },
  { id: 104, category: "CSS", subcategory: "Flexbox", level: "intermediate", q: "flex-grow, flex-shrink, flex-basis là gì?", a: "`flex-basis`: kích thước ban đầu (trước grow/shrink). `flex-grow`: tỷ lệ phân bổ không gian thừa (0 = không grow). `flex-shrink`: tỷ lệ co lại khi thiếu space (0 = không shrink). Shorthand: `flex: grow shrink basis`." },
  { id: 105, category: "CSS", subcategory: "Flexbox", level: "intermediate", q: "flex-wrap hoạt động thế nào?", a: "`nowrap` (mặc định, tất cả trên 1 dòng, co lại nếu cần). `wrap` (xuống dòng khi hết space). `wrap-reverse` (xuống dòng ngược). Khi wrap, dùng `align-content` căn chỉnh các dòng." },
  { id: 106, category: "CSS", subcategory: "Flexbox", level: "intermediate", q: "Gap property trong Flexbox là gì?", a: "Tạo khoảng cách giữa flex items mà không cần margin. `gap: 16px` (cả 2 chiều), `row-gap` và `column-gap` riêng. Ưu điểm: không gây margin collapse, không có khoảng cách thừa ở edge." },
  { id: 107, category: "CSS", subcategory: "Flexbox", level: "intermediate", q: "align-self dùng để làm gì?", a: "Override align-items cho 1 flex item cụ thể. Values: auto (theo parent), flex-start, flex-end, center, baseline, stretch. Cho phép 1 item căn khác so với các items còn lại trong container." },
  { id: 108, category: "CSS", subcategory: "Flexbox", level: "advanced", q: "Làm thế nào để center cả horizontal và vertical bằng Flexbox?", a: "Container: `display: flex; justify-content: center; align-items: center;`. Hoặc: `display: flex;` + child: `margin: auto;`. Đây là cách đơn giản nhất để center element trong CSS hiện đại." },

  // === CSS: Grid (109-125) ===
  { id: 109, category: "CSS", subcategory: "Grid", level: "beginner", q: "CSS Grid là gì? Khác Flexbox thế nào?", a: "Layout 2 chiều (rows VÀ columns cùng lúc). Flexbox cho 1 chiều (row hoặc column). Grid tốt cho page layout tổng thể, Flexbox cho component layout. Có thể kết hợp cả hai." },
  { id: 110, category: "CSS", subcategory: "Grid", level: "beginner", q: "fr unit là gì?", a: "Fractional unit - đơn vị tỷ lệ trong Grid. `grid-template-columns: 1fr 2fr` = cột 2 gấp đôi cột 1. Fr phân bổ không gian còn lại sau khi trừ fixed sizes. Linh hoạt hơn % vì tự tính gap." },
  { id: 111, category: "CSS", subcategory: "Grid", level: "intermediate", q: "grid-template-columns và grid-template-rows hoạt động thế nào?", a: "Định nghĩa số lượng và kích thước columns/rows. Ví dụ: `grid-template-columns: 200px 1fr 1fr` = 1 cột 200px + 2 cột equal. Dùng `repeat(3, 1fr)` cho 3 cột bằng nhau. Kết hợp minmax(), auto-fit, auto-fill." },
  { id: 112, category: "CSS", subcategory: "Grid", level: "intermediate", q: "auto-fit và auto-fill khác nhau?", a: "Cả hai dùng với `repeat()` để tự động tạo columns. `auto-fill`: tạo tracks rỗng nếu còn space. `auto-fit`: collapse tracks rỗng, items stretch fill space. auto-fit phổ biến hơn cho responsive grids." },
  { id: 113, category: "CSS", subcategory: "Grid", level: "intermediate", q: "minmax() function dùng để làm gì?", a: "Giới hạn min/max kích thước track. `minmax(200px, 1fr)` = tối thiểu 200px, tối đa bằng nhau. Kết hợp auto-fit: `repeat(auto-fit, minmax(250px, 1fr))` tạo responsive grid không cần media queries." },
  { id: 114, category: "CSS", subcategory: "Grid", level: "intermediate", q: "Grid template areas là gì?", a: "Đặt tên cho vùng trong grid bằng strings: `grid-template-areas: 'header header' 'sidebar main' 'footer footer'`. Items dùng `grid-area: header`. Trực quan, dễ đọc. Dùng `.` cho ô trống." },
  { id: 115, category: "CSS", subcategory: "Grid", level: "advanced", q: "Subgrid là gì?", a: "Cho phép grid item kế thừa track definitions từ parent grid. `grid-template-columns: subgrid`. Giải quyết vấn đề align content giữa các grid items. Firefox 71+, Safari 16+, Chrome 117+. Hiện đã widely supported." },
  { id: 116, category: "CSS", subcategory: "Grid", level: "advanced", q: "Grid placement (grid-column, grid-row) hoạt động thế nào?", a: "`grid-column: 1 / 3` = từ line 1 đến line 3 (span 2 columns). `grid-row: 1 / -1` = full height. `span 2` = chiếm 2 tracks. Dùng named lines hoặc numbers. Negative values đếm từ cuối." },

  // === CSS: Responsive & Animations (117-140) ===
  { id: 117, category: "CSS", subcategory: "Responsive", level: "beginner", q: "Responsive design là gì?", a: "Thiết kế web tự điều chỉnh giao diện theo kích thước màn hình (desktop, tablet, mobile). Dùng fluid layouts (%, fr), flexible images, media queries. Mobile-first approach được khuyến nghị." },
  { id: 118, category: "CSS", subcategory: "Responsive", level: "beginner", q: "Mobile-first approach là gì?", a: "Viết CSS cho mobile trước (base styles), dùng `min-width` media queries thêm styles cho màn hình lớn hơn. Ưu điểm: performance tốt hơn trên mobile, progressive enhancement, code gọn hơn." },
  { id: 119, category: "CSS", subcategory: "Responsive", level: "beginner", q: "Media queries dùng như thế nào?", a: "`@media (min-width: 768px) { ... }` áp dụng styles khi viewport >= 768px. Có thể kết hợp: `@media (min-width: 768px) and (max-width: 1024px)`. Breakpoints phổ biến: 640, 768, 1024, 1280px." },
  { id: 120, category: "CSS", subcategory: "Responsive", level: "intermediate", q: "clamp() function dùng để làm gì?", a: "`clamp(min, preferred, max)` giới hạn giá trị trong khoảng. Ví dụ: `font-size: clamp(1rem, 2.5vw, 2rem)` = fluid typography tự co giãn. Thay thế nhiều media queries, tạo responsive sizing mượt." },
  { id: 121, category: "CSS", subcategory: "Responsive", level: "intermediate", q: "Container queries là gì?", a: "Responsive theo kích thước container thay vì viewport. `@container (min-width: 400px) { ... }`. Container phải có `container-type: inline-size`. Giải quyết vấn đề component responsive độc lập với page layout." },
  { id: 122, category: "CSS", subcategory: "Responsive", level: "intermediate", q: "Viewport meta tag quan trọng thế nào?", a: "`<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">` bắt buộc cho responsive. Không có nó, mobile browsers zoom out để hiện toàn bộ trang desktop. device-width = screen width thực tế." },
  { id: 123, category: "CSS", subcategory: "Responsive", level: "intermediate", q: "Responsive images (srcset, sizes) hoạt động thế nào?", a: "`srcset` cung cấp nhiều phiên bản ảnh khác kích thước. `sizes` cho browser biết ảnh chiếm bao nhiêu viewport. Browser tự chọn ảnh phù hợp. Tiết kiệm bandwidth trên thiết bị nhỏ." },
  { id: 124, category: "CSS", subcategory: "Animations", level: "beginner", q: "CSS transition và animation khác nhau?", a: "Transition: chuyển đổi giữa 2 trạng thái khi trigger (hover, class change). Animation (@keyframes): phức tạp hơn, nhiều bước, có thể tự chạy, lặp lại. Transition cho interactions đơn giản, animation cho effects phức tạp." },
  { id: 125, category: "CSS", subcategory: "Animations", level: "beginner", q: "Transition properties gồm những gì?", a: "`transition-property` (CSS property nào). `transition-duration` (thời gian). `transition-timing-function` (ease, linear, cubic-bezier). `transition-delay` (delay). Shorthand: `transition: opacity 0.3s ease 0s`." },
  { id: 126, category: "CSS", subcategory: "Animations", level: "intermediate", q: "@keyframes hoạt động thế nào?", a: "Định nghĩa animation steps: `@keyframes fadeIn { from { opacity: 0 } to { opacity: 1 } }`. Dùng % cho nhiều bước: `0% { } 50% { } 100% { }`. Áp dụng: `animation: fadeIn 0.5s ease forwards`." },
  { id: 127, category: "CSS", subcategory: "Animations", level: "intermediate", q: "will-change property dùng để làm gì?", a: "Hint cho browser chuẩn bị trước cho animation/transition. `will-change: transform` tạo composite layer riêng, dùng GPU. Chỉ dùng khi thực sự cần, xóa khi animation xong. Lạm dụng tốn memory." },
  { id: 128, category: "CSS", subcategory: "Animations", level: "advanced", q: "Tại sao transform/opacity animate mượt hơn top/left?", a: "transform và opacity chỉ trigger composite step (GPU). top/left trigger layout + paint + composite (CPU-intensive). Layout recalculation tốn thời gian vì ảnh hưởng tất cả elements. Luôn ưu tiên transform: translate() cho di chuyển." },
  { id: 129, category: "CSS", subcategory: "Animations", level: "advanced", q: "Reflow và repaint là gì?", a: "Reflow (layout): tính toán lại vị trí/kích thước elements (tốn nhất). Repaint: vẽ lại pixels (ít tốn hơn). Composite: ghép layers (ít tốn nhất). Thay đổi width/height gây reflow. Thay đổi color chỉ repaint. Transform chỉ composite." },

  // === CSS: Modern Features (130-150) ===
  { id: 130, category: "CSS", subcategory: "Modern CSS", level: "beginner", q: "CSS Custom Properties (biến CSS) là gì?", a: "Biến trong CSS: `--primary: #2563eb`. Truy cập: `var(--primary)`. Khai báo trong `:root` cho global. Có cascade/inheritance, thay đổi runtime bằng JS. Hỗ trợ fallback: `var(--color, blue)`." },
  { id: 131, category: "CSS", subcategory: "Modern CSS", level: "intermediate", q: "CSS Custom Properties khác SASS variables thế nào?", a: "Custom Properties: runtime, cascade/inherit, thay đổi bằng JS, scope theo DOM. SASS variables: compile-time, flat scope, không thay đổi runtime. Custom Properties mạnh hơn cho theming, responsive. SASS tốt cho calculations phức tạp." },
  { id: 132, category: "CSS", subcategory: "Modern CSS", level: "intermediate", q: "@supports rule dùng để làm gì?", a: "Feature detection trong CSS. `@supports (display: grid) { ... }` chỉ áp dụng styles khi browser hỗ trợ. Dùng `not`, `and`, `or` kết hợp. Progressive enhancement: base styles + @supports cho features mới." },
  { id: 133, category: "CSS", subcategory: "Modern CSS", level: "intermediate", q: "CSS logical properties là gì?", a: "Thay physical properties (left/right/top/bottom) bằng logical (inline-start/inline-end/block-start/block-end). Tự động adapt theo writing direction (LTR/RTL). `margin-inline-start` thay `margin-left`. Quan trọng cho i18n." },
  { id: 134, category: "CSS", subcategory: "Modern CSS", level: "intermediate", q: "aspect-ratio property dùng để làm gì?", a: "Duy trì tỷ lệ width/height. `aspect-ratio: 16/9` hoặc `aspect-ratio: 1` (square). Thay thế padding-bottom hack cũ. Kết hợp object-fit cho images/videos giữ tỷ lệ trong container." },
  { id: 135, category: "CSS", subcategory: "Modern CSS", level: "intermediate", q: "scroll-snap CSS là gì?", a: "Native scroll snapping không cần JS. Container: `scroll-snap-type: x mandatory`. Items: `scroll-snap-align: start`. Dùng cho carousels, full-page scroll, image galleries. `mandatory` snap luôn, `proximity` snap khi gần." },
  { id: 136, category: "CSS", subcategory: "Modern CSS", level: "advanced", q: "Color spaces mới trong CSS (oklch, lab) là gì?", a: "oklch/oklab: perceptually uniform color spaces - thay đổi lightness/chroma/hue đều đặn hơn sRGB. Gamut rộng hơn (P3 displays). `color: oklch(70% 0.15 250)`. Tốt hơn cho design systems, gradients không bị muddy." },
  { id: 137, category: "CSS", subcategory: "Modern CSS", level: "advanced", q: "CSS Nesting native hoạt động thế nào?", a: "Nesting selectors trong CSS thuần (giống SASS). `.card { & .title { ... } &:hover { ... } }`. `&` represent parent selector. Hỗ trợ Chrome 120+ (relaxed syntax), Safari 17.2+, Firefox 117+. Giảm nhu cầu preprocessors." },
  { id: 138, category: "CSS", subcategory: "Modern CSS", level: "advanced", q: "@layer (Cascade Layers) là gì?", a: "Quản lý specificity theo layers: `@layer base, components, utilities`. Styles trong layer có thứ tự ưu tiên rõ ràng bất kể specificity. Layer sau override layer trước. Giải quyết specificity wars." },

  // === CSS: Architecture & Performance (139-155) ===
  { id: 139, category: "CSS", subcategory: "Architecture", level: "beginner", q: "BEM (Block Element Modifier) là gì?", a: "Naming convention: `block__element--modifier`. Block: component độc lập (`.card`). Element: phần trong block (`.card__title`). Modifier: biến thể (`.card--featured`). Tránh nesting sâu, dễ maintain." },
  { id: 140, category: "CSS", subcategory: "Architecture", level: "intermediate", q: "Utility-first CSS (Tailwind) là gì?", a: "Methodology viết styles bằng utility classes nhỏ trực tiếp trong HTML: `class=\"flex items-center gap-4 p-4 bg-white rounded-lg\"`. Tailwind CSS là framework phổ biến nhất. Ưu điểm: phát triển nhanh, design consistent, không đặt tên class, tree-shake tự động xóa unused CSS (bundle nhỏ). Nhược: HTML verbose, learning curve ban đầu. So với BEM: ít abstraction hơn, productivity cao hơn cho hầu hết teams." },
  { id: 141, category: "CSS", subcategory: "Architecture", level: "intermediate", q: "CSS Modules là gì?", a: "File CSS scoped theo component, class names tự động unique (hash). `import styles from './Button.module.css'`. Tránh conflicts, dùng với React/Next.js. Compile time, không runtime overhead." },
  { id: 142, category: "CSS", subcategory: "Architecture", level: "intermediate", q: "CSS-in-JS là gì? Ưu nhược điểm?", a: "Viết CSS trong JavaScript (styled-components, Emotion). Ưu: scoped, dynamic styling, co-located. Nhược: runtime cost, bundle size, SSR complexity. Xu hướng mới: zero-runtime CSS-in-JS (Vanilla Extract, Panda CSS)." },
  { id: 143, category: "CSS", subcategory: "Performance", level: "intermediate", q: "Critical CSS là gì?", a: "CSS tối thiểu cần thiết để render above-the-fold content (phần user nhìn thấy đầu tiên). Cách dùng: inline critical CSS trong `<style>` tag ở `<head>`, phần CSS còn lại load async bằng `<link rel=\"preload\">` hoặc JS injection. Giải quyết vấn đề render-blocking CSS. Tools: Critical (npm), Critters (Webpack plugin). Cải thiện FCP và LCP đáng kể, đặc biệt trên mobile/3G." },
  { id: 144, category: "CSS", subcategory: "Performance", level: "intermediate", q: "PurgeCSS dùng để làm gì?", a: "Xóa CSS không sử dụng bằng cách scan HTML/JS files tìm class names. Giảm bundle size đáng kể (đặc biệt với Tailwind). Tích hợp sẵn trong Tailwind CSS. Cấu hình content paths chính xác để tránh xóa nhầm." },
  { id: 145, category: "CSS", subcategory: "Performance", level: "intermediate", q: "font-display property có những giá trị nào?", a: "`auto` (browser quyết định). `block` (ẩn text đến khi font load). `swap` (hiện fallback, swap khi ready - khuyến nghị). `fallback` (swap nhanh hoặc giữ fallback). `optional` (dùng nếu cached, không nếu chưa). swap tốt cho hiển thị nhanh (tránh FOIT) nhưng có thể gây CLS nếu không dùng `size-adjust`. Dùng `optional` nếu ưu tiên CLS." },
  { id: 146, category: "CSS", subcategory: "Performance", level: "advanced", q: "CSS containment (contain property) là gì?", a: "`contain: layout paint size` giới hạn scope rendering của element. Browser tối ưu: không recalculate bên ngoài contain boundary. `content-visibility: auto` auto-skip rendering off-screen elements. Cải thiện rendering performance." },
  { id: 147, category: "CSS", subcategory: "Performance", level: "advanced", q: "Layout thrashing là gì? Cách tránh?", a: "Đọc layout property (offsetHeight) rồi ngay lập tức ghi style → browser phải recalculate layout liên tục. Tránh bằng: batch reads trước writes, dùng transform thay top/left, dùng requestAnimationFrame." },

  // === CSS: Advanced Topics (148-200) ===
  { id: 148, category: "CSS", subcategory: "Advanced", level: "intermediate", q: "Backdrop-filter dùng để làm gì?", a: "Áp dụng filter effects (blur, brightness, contrast) cho background phía sau element. `backdrop-filter: blur(10px)` tạo frosted glass effect. Dùng cho modals, navigation bars, overlays. Cần background semi-transparent." },
  { id: 149, category: "CSS", subcategory: "Advanced", level: "intermediate", q: "Mix-blend-mode dùng để làm gì?", a: "Blend colors giữa element và background (giống Photoshop blend modes). Values: multiply, screen, overlay, darken, lighten, color-dodge, etc. Dùng cho text effects, image overlays, creative designs." },
  { id: 150, category: "CSS", subcategory: "Advanced", level: "intermediate", q: "CSS filters có những loại nào?", a: "`blur()`, `brightness()`, `contrast()`, `grayscale()`, `hue-rotate()`, `invert()`, `opacity()`, `saturate()`, `sepia()`, `drop-shadow()`. Kết hợp nhiều filters: `filter: blur(2px) brightness(1.2)`. GPU-accelerated." },
  { id: 151, category: "CSS", subcategory: "Advanced", level: "intermediate", q: "Gradient (linear, radial, conic) là gì?", a: "`linear-gradient(direction, color1, color2)`: dải màu thẳng. `radial-gradient()`: hình tròn/elip. `conic-gradient()`: hình quạt (pie chart). Dùng cho backgrounds, borders, text effects. Có thể repeating." },
  { id: 152, category: "CSS", subcategory: "Advanced", level: "intermediate", q: "object-fit và object-position dùng cho gì?", a: "`object-fit` kiểm soát cách image/video fit trong container: `cover` (fill, có thể crop), `contain` (fit, có thể letterbox), `fill` (stretch), `none`. `object-position` set vị trí focal point." },
  { id: 153, category: "CSS", subcategory: "Advanced", level: "intermediate", q: "clip-path dùng để làm gì?", a: "Cắt element theo hình dạng: `circle()`, `ellipse()`, `polygon()`, `inset()`, `path()`. Ví dụ: `clip-path: polygon(50% 0, 100% 100%, 0 100%)` tạo tam giác. Dùng cho creative shapes, reveal effects." },
  { id: 154, category: "CSS", subcategory: "Advanced", level: "intermediate", q: "Pointer-events property dùng khi nào?", a: "`pointer-events: none` làm element 'transparent' với mouse/touch - events pass through đến element phía dưới. Dùng cho overlays không cản tương tác, disabled states, decorative elements." },
  { id: 155, category: "CSS", subcategory: "Advanced", level: "advanced", q: "Scroll-driven animations là gì?", a: "API mới cho phép animation dựa trên scroll position thay vì time. `animation-timeline: scroll()` hoặc `view()`. Thay thế JS scroll listeners cho parallax, progress bars, reveal animations. Chrome 115+, Firefox 128+ (stable)." },
  { id: 156, category: "CSS", subcategory: "Advanced", level: "advanced", q: "CSS Anchor Positioning là gì?", a: "API mới cho phép position element relative với anchor element khác không cần JS. `anchor-name`, `position-anchor`, `inset-area`. Dùng cho tooltips, popovers, dropdown menus. Chrome 125+." },
  { id: 157, category: "CSS", subcategory: "Advanced", level: "advanced", q: "@property rule dùng để làm gì?", a: "Đăng ký custom property với type, initial value, inheritance. `@property --hue { syntax: '<angle>'; initial-value: 0deg; inherits: false }`. Cho phép animate custom properties (gradients), type checking." },
  { id: 158, category: "CSS", subcategory: "Advanced", level: "advanced", q: "CSS View Transitions API là gì?", a: "API tạo smooth transitions giữa DOM states hoặc page navigations. `document.startViewTransition()` snapshot trước→sau, animate sự khác biệt. Same-document: Chrome 111+. Cross-document (navigation): Chrome 126+. Dùng cho page transitions, list reordering, morph animations." },
  { id: 159, category: "CSS", subcategory: "Advanced", level: "advanced", q: "Popover API và CSS liên quan là gì?", a: "HTML `popover` attribute + CSS `::backdrop`, `:popover-open` pseudo-elements. Native popover không cần JS cho show/hide logic. Tự xử lý: top layer, light dismiss, focus trap. Thay thế nhiều JS popover libraries." },
  { id: 160, category: "CSS", subcategory: "Advanced", level: "advanced", q: "Tại sao nên dùng CSS Grid cho page layout thay vì float/position?", a: "Grid: 2D layout, responsive native (auto-fit, minmax), semantic, overlap dễ, gap spacing. Float: hack từ text wrapping, clearfix issues, fragile. Position: thoát flow, không responsive. Grid là standard hiện đại, được tất cả browsers hỗ trợ." },

  // === Thêm CSS nâng cao (161-200) ===
  { id: 161, category: "CSS", subcategory: "Advanced", level: "intermediate", q: "Text truncation (ellipsis) thực hiện thế nào?", a: "Single line: `white-space: nowrap; overflow: hidden; text-overflow: ellipsis`. Multi-line: `-webkit-line-clamp: 3; display: -webkit-box; -webkit-box-orient: vertical; overflow: hidden`. line-clamp đã widely supported." },
  { id: 162, category: "CSS", subcategory: "Advanced", level: "intermediate", q: "CSS counter là gì?", a: "Biến đếm tự động trong CSS. `counter-reset: section` khởi tạo. `counter-increment: section` tăng. `content: counter(section)` hiển thị trong ::before/::after. Dùng cho tự động đánh số headings, lists tùy chỉnh." },
  { id: 163, category: "CSS", subcategory: "Advanced", level: "intermediate", q: "Variable fonts là gì?", a: "1 file font chứa nhiều variations (weight, width, slant) thay vì nhiều files riêng. Giảm requests và file size. Dùng `font-variation-settings` hoặc CSS properties (font-weight: 100-900 liên tục). Smooth animations giữa weights." },
  { id: 164, category: "CSS", subcategory: "Advanced", level: "intermediate", q: "prefers-reduced-motion media query dùng khi nào?", a: "Tôn trọng accessibility settings của user muốn giảm animations. `@media (prefers-reduced-motion: reduce) { * { animation: none; transition: none; } }`. Quan trọng cho users có vestibular disorders." },
  { id: 165, category: "CSS", subcategory: "Advanced", level: "intermediate", q: "prefers-color-scheme media query là gì?", a: "Detect system dark/light mode preference. `@media (prefers-color-scheme: dark) { ... }`. Kết hợp CSS custom properties cho theming. Base styles = light, dark media query override colors." },
  { id: 166, category: "CSS", subcategory: "Responsive", level: "intermediate", q: "picture element và source dùng thế nào?", a: "`<picture>` chứa nhiều `<source>` với media conditions hoặc type khác nhau, fallback `<img>`. Art direction: thay đổi ảnh theo viewport. Format: WebP/AVIF fallback JPEG. Browser chọn source phù hợp nhất." },
  { id: 167, category: "CSS", subcategory: "Responsive", level: "advanced", q: "Fluid typography công thức thế nào?", a: "Dùng `clamp()`: `font-size: clamp(1rem, 0.5rem + 1.5vw, 2rem)`. Tính: preferred = minSize + (maxSize - minSize) * ((100vw - minViewport) / (maxViewport - minViewport)). Hoặc dùng tools: utopia.fyi." },
  { id: 168, category: "CSS", subcategory: "Architecture", level: "intermediate", q: "Tailwind CSS so với CSS thuần - khi nào dùng gì?", a: "Tailwind: projects lớn, team, consistent design, rapid prototyping. CSS thuần: projects nhỏ, custom creative designs, learning. Tailwind tốt cho apps, CSS thuần tốt cho sites cần unique styling." },
  { id: 169, category: "CSS", subcategory: "Architecture", level: "advanced", q: "Design tokens là gì?", a: "Giá trị design được đặt tên: colors, spacing, typography, shadows. Platform-agnostic (JSON), transform sang CSS vars, SASS, JS. Single source of truth cho design system. Tools: Style Dictionary, Figma Tokens." },
  { id: 170, category: "CSS", subcategory: "Performance", level: "advanced", q: "content-visibility: auto là gì?", a: "Skip rendering off-screen elements hoàn toàn. Browser chỉ render khi element gần viewport. Cải thiện initial rendering performance đáng kể cho long pages. Cần `contain-intrinsic-size` để giữ scroll height chính xác." },
  { id: 171, category: "CSS", subcategory: "Advanced", level: "intermediate", q: "box-shadow vs filter: drop-shadow() khác nhau?", a: "`box-shadow` theo hình chữ nhật (box). `drop-shadow` theo shape thực tế (hỗ trợ transparent PNG, clip-path). drop-shadow không hỗ trợ spread value và inset. box-shadow nhanh hơn." },
  { id: 172, category: "CSS", subcategory: "Advanced", level: "intermediate", q: "currentColor keyword dùng để làm gì?", a: "Reference đến giá trị `color` hiện tại. Dùng cho: `border-color: currentColor`, `fill: currentColor` (SVG). Kế thừa color từ parent. Giảm lặp code, SVG icons tự thay đổi màu theo text." },
  { id: 173, category: "CSS", subcategory: "Advanced", level: "intermediate", q: "isolation property dùng để làm gì?", a: "`isolation: isolate` tạo stacking context mới. Element bên trong không blend với bên ngoài. Giải quyết z-index conflicts. Dùng khi component cần isolated z-index scope." },
  { id: 174, category: "CSS", subcategory: "Advanced", level: "advanced", q: "CSS Houdini là gì?", a: "Tập hợp APIs cho phép extend CSS engine: Paint API (custom backgrounds), Layout API (custom display), Typed OM, Properties & Values API. Cho phép tạo CSS features mới bằng JavaScript. Hỗ trợ còn hạn chế." },
  { id: 175, category: "CSS", subcategory: "Responsive", level: "intermediate", q: "Breakpoints nên đặt theo thiết bị hay theo content?", a: "Nên theo content. Resize browser và thêm breakpoint khi layout 'vỡ'. Không phụ thuộc device-specific sizes (thay đổi liên tục). Content-based breakpoints linh hoạt hơn, future-proof." },
  { id: 176, category: "CSS", subcategory: "Architecture", level: "intermediate", q: "OOCSS (Object-Oriented CSS) là gì?", a: "Tách structure khỏi skin, tách container khỏi content. Tạo reusable objects: `.btn` (structure) + `.btn-primary` (skin). Giảm duplication, tăng scalability. Nicole Sullivan sáng tạo. Nguyên tắc nền tảng cho BEM, Tailwind." },
  { id: 177, category: "CSS", subcategory: "Architecture", level: "intermediate", q: "SMACSS (Scalable and Modular Architecture for CSS) là gì?", a: "Phân loại CSS thành 5 categories: Base (defaults), Layout (page sections), Module (reusable components), State (overrides), Theme (visual theming). Giúp tổ chức CSS quy mô lớn. Jonathan Snook sáng tạo." },
  { id: 178, category: "CSS", subcategory: "Performance", level: "intermediate", q: "Composite layers trong browser là gì?", a: "Browser tách elements thành layers riêng, composite chúng bằng GPU. Trigger composite layer: transform, opacity, will-change, position: fixed. Tách layer = animate mượt hơn nhưng tốn memory. Kiểm tra trong DevTools > Layers." },
  { id: 179, category: "CSS", subcategory: "Performance", level: "intermediate", q: "CSS selector performance quan trọng không?", a: "Với browser hiện đại, selector performance gần như không đáng lo. Browser đọc selectors phải-sang-trái. Tránh: universal * selector lồng sâu, attribute selectors phức tạp. Focus vào: giảm CSS file size, critical CSS, giảm unused CSS." },
  { id: 180, category: "CSS", subcategory: "Advanced", level: "intermediate", q: "Scrollbar styling thực hiện thế nào?", a: "Webkit: `::-webkit-scrollbar`, `::-webkit-scrollbar-thumb`, `::-webkit-scrollbar-track`. Standard: `scrollbar-width: thin`, `scrollbar-color: thumb-color track-color`. Webkit chi tiết hơn nhưng non-standard." },
  { id: 181, category: "CSS", subcategory: "Advanced", level: "intermediate", q: "Shape-outside dùng để làm gì?", a: "Wrap text quanh hình dạng phi chữ nhật. `shape-outside: circle(50%)` hoặc `ellipse()`, `polygon()`, `url(image.png)`. Chỉ hoạt động với floated elements. Dùng cho magazine-style text layouts." },
  { id: 182, category: "CSS", subcategory: "Advanced", level: "intermediate", q: "accent-color property là gì?", a: "Thay đổi màu mặc định của form controls (checkbox, radio, range, progress) chỉ với 1 property. `accent-color: #2563eb`. Đơn giản nhất để style form controls consistently mà không cần custom components." },
  { id: 183, category: "CSS", subcategory: "Advanced", level: "intermediate", q: "CSS math functions (calc, min, max, clamp) khác nhau?", a: "`calc()`: tính toán (mixed units: `calc(100% - 2rem)`). `min()`: giá trị nhỏ nhất. `max()`: giá trị lớn nhất. `clamp(min, preferred, max)`: giới hạn trong khoảng. Kết hợp: `width: min(90%, 1200px)` thay max-width." },
  { id: 184, category: "CSS", subcategory: "Selectors", level: "advanced", q: ":focus-visible vs :focus khác nhau?", a: "`:focus` trigger mọi lúc element nhận focus (cả mouse click). `:focus-visible` chỉ khi focus cần visible indicator (keyboard navigation). Dùng `:focus-visible` cho focus rings: chỉ hiện khi dùng keyboard, không khi click." },
  { id: 185, category: "CSS", subcategory: "Modern CSS", level: "advanced", q: "CSS scope proposal (@scope) là gì?", a: "`@scope (.card) to (.card__content)` giới hạn styles trong phạm vi. Selectors chỉ match bên trong scope root, dừng tại scope limit. Giải quyết style leaking, thay thế Shadow DOM cho component scoping. Chrome 118+." },
  { id: 186, category: "CSS", subcategory: "Modern CSS", level: "advanced", q: "color-mix() function dùng để làm gì?", a: "`color-mix(in srgb, red 30%, blue)` trộn 2 màu. Dùng cho: tạo hover states (lighten/darken), opacity-like effects, palette generation. Hỗ trợ multiple color spaces (srgb, oklch, lab)." },
  { id: 187, category: "CSS", subcategory: "Modern CSS", level: "intermediate", q: "Tại sao oklch tốt hơn hsl cho design systems?", a: "oklch perceptually uniform: cùng chroma/lightness thay đổi hue → perceived brightness giữ nguyên (hsl không đảm bảo). Gamut rộng hơn (P3). Tạo color palettes consistent hơn. l=lightness, c=chroma, h=hue." },
  { id: 188, category: "CSS", subcategory: "Advanced", level: "advanced", q: "Tại sao tránh dùng vw cho font-size đơn lẻ?", a: "vw không respects user zoom settings (accessibility issue). Font quá nhỏ trên mobile, quá lớn trên desktop. Dùng `clamp()` kết hợp rem + vw: `clamp(1rem, 0.5rem + 1vw, 1.5rem)`. Đảm bảo min/max bounds." },
  { id: 189, category: "CSS", subcategory: "Performance", level: "advanced", q: "Cách tối ưu Cumulative Layout Shift (CLS)?", a: "Set width/height hoặc aspect-ratio cho images/videos. Reserve space cho ads/embeds. font-display: swap + size-adjust. Tránh inject content phía trên viewport. Tránh layout shifts từ web fonts loading." },
  { id: 190, category: "CSS", subcategory: "Architecture", level: "advanced", q: "Atomic CSS (functional CSS) philosophy là gì?", a: "Mỗi class làm 1 việc: `.flex`, `.mt-4`, `.text-center`. Composition qua nhiều classes. Ưu: bundle size nhỏ (reuse classes), no naming, predictable. Nhược: verbose HTML. Tailwind CSS là implementation phổ biến nhất." },
  { id: 191, category: "CSS", subcategory: "Architecture", level: "advanced", q: "Khi nào nên dùng CSS-in-JS vs CSS Modules vs Tailwind?", a: "CSS-in-JS: dynamic theming phức tạp, component libraries. CSS Modules: scoped styles đơn giản, SSR-friendly, zero runtime. Tailwind: rapid development, design system consistent. Xu hướng: zero-runtime (Tailwind, CSS Modules) > runtime CSS-in-JS." },
  { id: 192, category: "CSS", subcategory: "Advanced", level: "intermediate", q: "Gradient border thực hiện thế nào?", a: "Cách 1: `border-image: linear-gradient(...) 1`. Cách 2: background gradient + padding (inner background che content area). Cách 3: `@property` + conic-gradient. border-image không hỗ trợ border-radius." },
  { id: 193, category: "CSS", subcategory: "Advanced", level: "intermediate", q: "Dark mode implementation best practices?", a: "Dùng CSS custom properties cho colors. `@media (prefers-color-scheme: dark)` hoặc class-based toggle. Tránh hardcode colors. Dùng oklch cho auto dark palette. Test contrast ratios. Lưu preference vào localStorage." },
  { id: 194, category: "CSS", subcategory: "Advanced", level: "intermediate", q: "user-select property dùng khi nào?", a: "`user-select: none` ngăn chọn text (buttons, drag handles). `user-select: all` chọn toàn bộ khi click (code blocks, tokens). `user-select: text` (mặc định). Cẩn thận: none ảnh hưởng accessibility." },
  { id: 195, category: "CSS", subcategory: "Advanced", level: "intermediate", q: "touch-action property dùng để làm gì?", a: "Kiểm soát browser handling touch gestures. `touch-action: none` disable zoom/scroll (canvas, games). `manipulation` disable double-tap zoom (loại bỏ 300ms click delay). Quan trọng cho touch-heavy UIs." },
  { id: 196, category: "CSS", subcategory: "Advanced", level: "advanced", q: "CSS Typed Object Model (Typed OM) là gì?", a: "JavaScript API thao tác CSS values dưới dạng typed objects thay vì strings. `el.attributeStyleMap.set('width', CSS.px(100))`. Performance tốt hơn, type-safe, less error-prone. Một phần của Houdini. Chrome supported." },
  { id: 197, category: "CSS", subcategory: "Responsive", level: "advanced", q: "Container queries so với media queries - khi nào dùng gì?", a: "Media queries: page-level responsive, viewport-based breakpoints. Container queries: component-level responsive, self-contained. Kết hợp: media queries cho overall layout, container queries cho reusable components trong mọi context." },
  { id: 198, category: "CSS", subcategory: "Performance", level: "advanced", q: "Cách optimize Largest Contentful Paint (LCP) bằng CSS?", a: "Inline critical CSS trong head. Preload hero images/fonts. Tránh render-blocking CSS. font-display: swap. Tránh @import (serial loading). Background images: dùng `<img>` thay. Giảm CSS file size. Tránh complex selectors trên LCP element." },
  { id: 199, category: "CSS", subcategory: "Performance", level: "advanced", q: "Cách giảm CSS bundle size?", a: "PurgeCSS/Tailwind JIT: xóa unused classes. Tree shaking CSS Modules. Minification (cssnano). Tránh duplicate styles. Dùng shorthand properties. CSS compression (Brotli/gzip). Code splitting CSS theo route. Audit với Coverage DevTools." },
  { id: 200, category: "CSS", subcategory: "Advanced", level: "advanced", q: "Tương lai CSS: những features nào đang phát triển?", a: "Interop 2024-2025 focus: anchor positioning, scroll-driven animations, view transitions, @scope, CSS nesting, trigonometric functions, relative color syntax. CSS đang evolve nhanh, giảm nhu cầu JS cho nhiều UI patterns." },
]
